  6â†’import { Emitter, Event } from './event.js';
  7â†’import { DisposableStore, IDisposable } from './lifecycle.js';
  8â†’
  9â†’export interface CancellationToken {
 10â†’
 11â†’	/**
 12â†’	 * A flag signalling is cancellation has been requested.
 13â†’	 */
 14â†’	readonly isCancellationRequested: boolean;
 15â†’
 16â†’	/**
 17â†’	 * An event which fires when cancellation is requested. This event
 18â†’	 * only ever fires `once` as cancellation can only happen once. Listeners
 19â†’	 * that are registered after cancellation will be called (next event loop run),
 20â†’	 * but also only once.
 21â†’	 *
 22â†’	 * @event
 23â†’	 */
 24â†’	readonly onCancellationRequested: (listener: (e: void) => unknown, thisArgs?: unknown, disposables?: IDisposable[]) => IDisposable;
 25â†’}
 26â†’
 27â†’const shortcutEvent: Event<void> = Object.freeze(function (callback, context?): IDisposable {
 28â†’	const handle = setTimeout(callback.bind(context), 0);
 29â†’	return { dispose() { clearTimeout(handle); } };
 30â†’});
 31â†’
 32â†’export namespace CancellationToken {
 33â†’
 34â†’	export function isCancellationToken(thing: unknown): thing is CancellationToken {
 35â†’		if (thing === CancellationToken.None || thing === CancellationToken.Cancelled) {
 36â†’			return true;
 37â†’		}
 38â†’		if (thing instanceof MutableToken) {
 39â†’			return true;
 40â†’		}
 41â†’		if (!thing || typeof thing !== 'object') {
 42â†’			return false;
 43â†’		}
 44â†’		return typeof (thing as CancellationToken).isCancellationRequested === 'boolean'
 45â†’			&& typeof (thing as CancellationToken).onCancellationRequested === 'function';
 46â†’	}
 47â†’
 48â†’
 49â†’	export const None = Object.freeze<CancellationToken>({
 50â†’		isCancellationRequested: false,
 51â†’		onCancellationRequested: Event.None
 52â†’	});
 53â†’
 54â†’	export const Cancelled = Object.freeze<CancellationToken>({
 55â†’		isCancellationRequested: true,
 56â†’		onCancellationRequested: shortcutEvent
 57â†’	});
 58â†’}
 59â†’
 60â†’class MutableToken implements CancellationToken {
 61â†’
 62â†’	private _isCancelled: boolean = false;
 63â†’	private _emitter: Emitter<void> | null = null;
 64â†’
 65â†’	public cancel() {
 66â†’		if (!this._isCancelled) {
 67â†’			this._isCancelled = true;
 68â†’			if (this._emitter) {
 69â†’				this._emitter.fire(undefined);
 70â†’				this.dispose();
 71â†’			}
 72â†’		}
 73â†’	}
 74â†’
 75â†’	get isCancellationRequested(): boolean {
 76â†’		return this._isCancelled;
 77â†’	}
 78â†’
 79â†’	get onCancellationRequested(): Event<void> {
 80â†’		if (this._isCancelled) {
 81â†’			return shortcutEvent;
 82â†’		}
 83â†’		if (!this._emitter) {
 84â†’			this._emitter = new Emitter<void>();
 85â†’		}
 86â†’		return this._emitter.event;
 87â†’	}
 88â†’
 89â†’	public dispose(): void {
 90â†’		if (this._emitter) {
 91â†’			this._emitter.dispose();
 92â†’			this._emitter = null;
 93â†’		}
 94â†’	}
 95â†’}
 96â†’
 97â†’export class CancellationTokenSource {
 98â†’
 99â†’	private _token?: CancellationToken = undefined;
100â†’	private _parentListener?: IDisposable = undefined;
101â†’
102â†’	constructor(parent?: CancellationToken) {
103â†’		this._parentListener = parent && parent.onCancellationRequested(this.cancel, this);
104â†’	}
105â†’
106â†’	get token(): CancellationToken {
107â†’		if (!this._token) {
108â†’			// be lazy and create the token only when
109â†’			// actually needed
110â†’			this._token = new MutableToken();
111â†’		}
112â†’		return this._token;
113â†’	}
114â†’
115â†’	cancel(): void {
116â†’		if (!this._token) {
117â†’			// save an object by returning the default
118â†’			// cancelled token when cancellation happens
119â†’			// before someone asks for the token
120â†’			this._token = CancellationToken.Cancelled;
121â†’
122â†’		} else if (this._token instanceof MutableToken) {
123â†’			// actually cancel
124â†’			this._token.cancel();
125â†’		}
126â†’	}
127â†’
128â†’	dispose(cancel: boolean = false): void {
129â†’		if (cancel) {
130â†’			this.cancel();
131â†’		}
132â†’		this._parentListener?.dispose();
133â†’		if (!this._token) {
134â†’			// ensure to initialize with an empty token if we had none
135â†’			this._token = CancellationToken.None;
136â†’
137â†’		} else if (this._token instanceof MutableToken) {
138â†’			// actually dispose
139â†’			this._token.dispose();
140â†’		}
141â†’	}
142â†’}
143â†’
144â†’export function cancelOnDispose(store: DisposableStore): CancellationToken {
145â†’	const source = new CancellationTokenSource();
146â†’	store.add({ dispose() { source.cancel(); } });
147â†’	return source.token;
148â†’}
149â†’
150â†’/**
151â†’ * A pool that aggregates multiple cancellation tokens. The pool's own token
152â†’ * (accessible via `pool.token`) is cancelled only after every token added
153â†’ * to the pool has been cancelled. Adding tokens after the pool token has
154â†’ * been cancelled has no effect.
155â†’ */
156â†’export class CancellationTokenPool {
157â†’
158â†’	private readonly _source = new CancellationTokenSource();
159â†’	private readonly _listeners = new DisposableStore();
160â†’
161â†’	private _total: number = 0;
162â†’	private _cancelled: number = 0;
163â†’	private _isDone: boolean = false;
164â†’
165â†’	get token(): CancellationToken {
166â†’		return this._source.token;
167â†’	}
168â†’
169â†’	/**
170â†’	 * Add a token to the pool. If the token is already cancelled it is counted
171â†’	 * immediately. Tokens added after the pool token has been cancelled are ignored.
172â†’	 */
173â†’	add(token: CancellationToken): void {
174â†’		if (this._isDone) {
175â†’			return;
176â†’		}
177â†’
178â†’		this._total++;
179â†’
180â†’		if (token.isCancellationRequested) {
181â†’			this._cancelled++;
182â†’			this._check();
183â†’			return;
184â†’		}
185â†’
186â†’		const d = token.onCancellationRequested(() => {
187â†’			d.dispose();
188â†’			this._cancelled++;
189â†’			this._check();
190â†’		});
191â†’		this._listeners.add(d);
192â†’	}
193â†’
194â†’	private _check(): void {
195â†’		if (!this._isDone && this._total > 0 && this._total === this._cancelled) {
196â†’			this._isDone = true;
197â†’			this._listeners.dispose();
198â†’			this._source.cancel();
199â†’		}
200â†’	}
201â†’
202â†’	dispose(): void {
203â†’		this._listeners.dispose();
204â†’		this._source.dispose();
205â†’	}
206â†’}
207â†’

