301â†’// #endregion
302â†’
303â†’/**
304â†’ * An object that performs a cleanup operation when `.dispose()` is called.
305â†’ *
306â†’ * Some examples of how disposables are used:
307â†’ *
308â†’ * - An event listener that removes itself when `.dispose()` is called.
309â†’ * - A resource such as a file system watcher that cleans up the resource when `.dispose()` is called.
310â†’ * - The return value from registering a provider. When `.dispose()` is called, the provider is unregistered.
311â†’ */
312â†’export interface IDisposable {
313â†’	dispose(): void;
314â†’}
315â†’
316â†’/**
317â†’ * Check if `thing` is {@link IDisposable disposable}.
318â†’ */
319â†’export function isDisposable<E>(thing: E): thing is E & IDisposable {
320â†’	// eslint-disable-next-line local/code-no-any-casts
321â†’	return typeof thing === 'object' && thing !== null && typeof (<IDisposable><any>thing).dispose === 'function' && (<IDisposable><any>thing).dispose.length === 0;
322â†’}
323â†’
324â†’/**
325â†’ * Disposes of the value(s) passed in.
326â†’ */
327â†’export function dispose<T extends IDisposable>(disposable: T): T;
328â†’export function dispose<T extends IDisposable>(disposable: T | undefined): T | undefined;
329â†’export function dispose<T extends IDisposable, A extends Iterable<T> = Iterable<T>>(disposables: A): A;
330â†’export function dispose<T extends IDisposable>(disposables: Array<T>): Array<T>;
331â†’export function dispose<T extends IDisposable>(disposables: ReadonlyArray<T>): ReadonlyArray<T>;
332â†’export function dispose<T extends IDisposable>(arg: T | Iterable<T> | undefined): any {
333â†’	if (Iterable.is(arg)) {
334â†’		const errors: any[] = [];
335â†’
336â†’		for (const d of arg) {
337â†’			if (d) {
338â†’				try {
339â†’					d.dispose();
340â†’				} catch (e) {
341â†’					errors.push(e);
342â†’				}
343â†’			}
344â†’		}
345â†’
346â†’		if (errors.length === 1) {
347â†’			throw errors[0];
348â†’		} else if (errors.length > 1) {
349â†’			throw new AggregateError(errors, 'Encountered errors while disposing of store');
