 19â†’	constructor() {
 20â†’
 21â†’		this.listeners = [];
 22â†’
 23â†’		this.unexpectedErrorHandler = function (e: any) {
 24â†’			setTimeout(() => {
 25â†’				if (e.stack) {
 26â†’					if (ErrorNoTelemetry.isErrorNoTelemetry(e)) {
 27â†’						throw new ErrorNoTelemetry(e.message + '\n\n' + e.stack);
 28â†’					}
 29â†’
 30â†’					throw new Error(e.message + '\n\n' + e.stack);
 31â†’				}
 32â†’
 33â†’				throw e;
 34â†’			}, 0);
 35â†’		};
 36â†’	}
 37â†’
 38â†’	addListener(listener: ErrorListenerCallback): ErrorListenerUnbind {
 39â†’		this.listeners.push(listener);
 40â†’
 41â†’		return () => {
 42â†’			this._removeListener(listener);
 43â†’		};
 44â†’	}
 45â†’
 46â†’	private emit(e: any): void {
 47â†’		this.listeners.forEach((listener) => {
 48â†’			listener(e);
 49â†’		});
 50â†’	}
 51â†’
 52â†’	private _removeListener(listener: ErrorListenerCallback): void {
 53â†’		this.listeners.splice(this.listeners.indexOf(listener), 1);
 54â†’	}
 55â†’
 56â†’	setUnexpectedErrorHandler(newUnexpectedErrorHandler: (e: any) => void): void {
 57â†’		this.unexpectedErrorHandler = newUnexpectedErrorHandler;
 58â†’	}
 59â†’
 60â†’	getUnexpectedErrorHandler(): (e: any) => void {
 61â†’		return this.unexpectedErrorHandler;
 62â†’	}
 63â†’
 64â†’	onUnexpectedError(e: any): void {
 65â†’		this.unexpectedErrorHandler(e);
