139â†’export function transformErrorForSerialization(error: any): any {
140â†’	if (error instanceof Error) {
141â†’		const { name, message, cause } = error;
142â†’		// eslint-disable-next-line local/code-no-any-casts
143â†’		const stack: string = (<any>error).stacktrace || (<any>error).stack;
144â†’		return {
145â†’			$isError: true,
146â†’			name,
147â†’			message,
148â†’			stack,
149â†’			noTelemetry: ErrorNoTelemetry.isErrorNoTelemetry(error),
150â†’			cause: cause ? transformErrorForSerialization(cause) : undefined,
151â†’			code: (<ErrorWithCode>error).code
152â†’		};
153â†’	}
154â†’
155â†’	// return as is
156â†’	return error;
157â†’}
