159â†’export function transformErrorFromSerialization(data: SerializedError): Error {
160â†’	let error: Error;
161â†’	if (data.noTelemetry) {
162â†’		error = new ErrorNoTelemetry();
163â†’	} else {
164â†’		error = new Error();
165â†’		error.name = data.name;
166â†’	}
167â†’	error.message = data.message;
168â†’	error.stack = data.stack;
169â†’	if (data.code) {
170â†’		(<ErrorWithCode>error).code = data.code;
171â†’	}
172â†’	if (data.cause) {
173â†’		error.cause = transformErrorFromSerialization(data.cause);
174â†’	}
175â†’	return error;
176â†’}
