 20â†’export interface CancelablePromise<T> extends Promise<T> {
 21â†’	cancel(): void;
 22â†’}
 23â†’
 24â†’/**
 25â†’ * Returns a promise that can be cancelled using the provided cancellation token.
 26â†’ *
 27â†’ * @remarks When cancellation is requested, the promise will be rejected with a {@link CancellationError}.
 28â†’ * If the promise resolves to a disposable object, it will be automatically disposed when cancellation
 29â†’ * is requested.
 30â†’ *
 31â†’ * @param callback A function that accepts a cancellation token and returns a promise
 32â†’ * @returns A promise that can be cancelled
 33â†’ */
 34â†’export function createCancelablePromise<T>(callback: (token: CancellationToken) => Promise<T>): CancelablePromise<T> {
 35â†’	const source = new CancellationTokenSource();
 36â†’
 37â†’	const thenable = callback(source.token);
 38â†’
 39â†’	let isCancelled = false;
 40â†’
 41â†’	const promise = new Promise<T>((resolve, reject) => {
 42â†’		const subscription = source.token.onCancellationRequested(() => {
 43â†’			isCancelled = true;
 44â†’			subscription.dispose();
 45â†’			reject(new CancellationError());
 46â†’		});
 47â†’		Promise.resolve(thenable).then(value => {
 48â†’			subscription.dispose();
 49â†’			source.dispose();
 50â†’
 51â†’			if (!isCancelled) {
 52â†’				resolve(value);
 53â†’
 54â†’			} else if (isDisposable(value)) {
 55â†’				// promise has been cancelled, result is disposable and will
 56â†’				// be cleaned up
 57â†’				value.dispose();
 58â†’			}
 59â†’		}, err => {
 60â†’			subscription.dispose();
 61â†’			source.dispose();
 62â†’			reject(err);
 63â†’		});
 64â†’	});
 65â†’
 66â†’	return <CancelablePromise<T>>new class {
 67â†’		cancel() {
 68â†’			source.cancel();
 69â†’			source.dispose();
 70â†’		}
 71â†’		then<TResult1 = T, TResult2 = never>(resolve?: ((value: T) => TResult1 | Promise<TResult1>) | undefined | null, reject?: ((reason: unknown) => TResult2 | Promise<TResult2>) | undefined | null): Promise<TResult1 | TResult2> {
 72â†’			return promise.then(resolve, reject);
 73â†’		}
 74â†’		catch<TResult = never>(reject?: ((reason: unknown) => TResult | Promise<TResult>) | undefined | null): Promise<T | TResult> {
 75â†’			return this.then(undefined, reject);
 76â†’		}
 77â†’		finally(onfinally?: (() => void) | undefined | null): Promise<T> {
 78â†’			return promise.finally(onfinally);
 79â†’		}
 80â†’	};
 81â†’}
