130â†’/**
131â†’ * Returns as soon as one of the promises resolves or rejects and cancels remaining promises
132â†’ */
133â†’export function raceCancellablePromises<T>(cancellablePromises: (CancelablePromise<T> | Promise<T>)[]): CancelablePromise<T> {
134â†’	let resolvedPromiseIndex = -1;
135â†’	const promises = cancellablePromises.map((promise, index) => promise.then(result => { resolvedPromiseIndex = index; return result; }));
136â†’	const promise = Promise.race(promises) as CancelablePromise<T>;
137â†’	promise.cancel = () => {
138â†’		cancellablePromises.forEach((cancellablePromise, index) => {
139â†’			if (index !== resolvedPromiseIndex && (cancellablePromise as CancelablePromise<T>).cancel) {
140â†’				(cancellablePromise as CancelablePromise<T>).cancel();
141â†’			}
142â†’		});
143â†’	};
144â†’	promise.finally(() => {
145â†’		promise.cancel();
146â†’	});
147â†’	return promise;
148â†’}
