150â†’export function raceTimeout<T>(promise: Promise<T>, timeout: number, onTimeout?: () => void): Promise<T | undefined> {
151â†’	let promiseResolve: ((value: T | undefined) => void) | undefined = undefined;
152â†’
153â†’	const timer = setTimeout(() => {
154â†’		promiseResolve?.(undefined);
155â†’		onTimeout?.();
156â†’	}, timeout);
157â†’
158â†’	return Promise.race([
159â†’		promise.finally(() => clearTimeout(timer)),
160â†’		new Promise<T | undefined>(resolve => promiseResolve = resolve)
161â†’	]);
162â†’}
