198â†’/**
199â†’ * A helper to prevent accumulation of sequential async tasks.
200â†’ *
201â†’ * Imagine a mail man with the sole task of delivering letters. As soon as
202â†’ * a letter submitted for delivery, he drives to the destination, delivers it
203â†’ * and returns to his base. Imagine that during the trip, N more letters were submitted.
204â†’ * When the mail man returns, he picks those N letters and delivers them all in a
205â†’ * single trip. Even though N+1 submissions occurred, only 2 deliveries were made.
206â†’ *
207â†’ * The throttler implements this via the queue() method, by providing it a task
208â†’ * factory. Following the example:
209â†’ *
210â†’ * 		const throttler = new Throttler();
211â†’ * 		const letters = [];
212â†’ *
213â†’ * 		function deliver() {
214â†’ * 			const lettersToDeliver = letters;
215â†’ * 			letters = [];
216â†’ * 			return makeTheTrip(lettersToDeliver);
217â†’ * 		}
218â†’ *
219â†’ * 		function onLetterReceived(l) {
220â†’ * 			letters.push(l);
221â†’ * 			throttler.queue(deliver);
222â†’ * 		}
