383â†’
384â†’	private deferred: IScheduledLater | null;
385â†’	private completionPromise: Promise<any> | null;
386â†’	private doResolve: ((value?: any | Promise<any>) => void) | null;
387â†’	private doReject: ((err: unknown) => void) | null;
388â†’	private task: ITask<T | Promise<T>> | null;
389â†’
390â†’	constructor(public defaultDelay: number | typeof MicrotaskDelay) {
391â†’		this.deferred = null;
392â†’		this.completionPromise = null;
393â†’		this.doResolve = null;
394â†’		this.doReject = null;
395â†’		this.task = null;
396â†’	}
397â†’
398â†’	trigger(task: ITask<T | Promise<T>>, delay = this.defaultDelay): Promise<T> {
399â†’		this.task = task;
400â†’		this.cancelTimeout();

400â†’		this.cancelTimeout();
401â†’
402â†’		if (!this.completionPromise) {
403â†’			this.completionPromise = new Promise((resolve, reject) => {
404â†’				this.doResolve = resolve;
405â†’				this.doReject = reject;
406â†’			}).then(() => {
407â†’				this.completionPromise = null;
408â†’				this.doResolve = null;
409â†’				if (this.task) {
410â†’					const task = this.task;
411â†’					this.task = null;
412â†’					return task();
413â†’				}
414â†’				return undefined;
415â†’			});
416â†’		}
417â†’
418â†’		const fn = () => {
419â†’			this.deferred = null;
420â†’			this.doResolve?.(null);
421â†’		};
422â†’
423â†’		this.deferred = delay === MicrotaskDelay ? microtaskDeferred(fn) : timeoutDeferred(delay, fn);
424â†’
425â†’		return this.completionPromise;
426â†’	}
427â†’
428â†’	isTriggered(): boolean {
429â†’		return !!this.deferred?.isTriggered();
430â†’	}
431â†’
432â†’	cancel(): void {
433â†’		this.cancelTimeout();
434â†’
435â†’		if (this.completionPromise) {
436â†’			this.doReject?.(new CancellationError());
437â†’			this.completionPromise = null;
438â†’		}
439â†’	}
440â†’
441â†’	private cancelTimeout(): void {
442â†’		this.deferred?.dispose();
443â†’		this.deferred = null;
444â†’	}
445â†’
446â†’	dispose(): void {
447â†’		this.cancel();
448â†’	}
449â†’}
