588â†’/**
589â†’ * Runs the provided list of promise factories in sequential order. The returned
590â†’ * promise will complete to an array of results from each promise.
591â†’ */
592â†’
593â†’export function sequence<T>(promiseFactories: ITask<Promise<T>>[]): Promise<T[]> {
594â†’	const results: T[] = [];
595â†’	let index = 0;
596â†’	const len = promiseFactories.length;
597â†’
598â†’	function next(): Promise<T> | null {
599â†’		return index < len ? promiseFactories[index++]() : null;
600â†’	}
601â†’
602â†’	function thenHandler(result: unknown): Promise<any> {
603â†’		if (result !== undefined && result !== null) {
604â†’			results.push(result as T);
605â†’		}
606â†’
607â†’		const n = next();
608â†’		if (n) {
609â†’			return n.then(thenHandler);
610â†’		}
611â†’
612â†’		return Promise.resolve(results);
613â†’	}
614â†’
615â†’	return Promise.resolve(null).then(thenHandler);
616â†’}
