618â†’export function first<T>(promiseFactories: ITask<Promise<T>>[], shouldStop: (t: T) => boolean = t => !!t, defaultValue: T | null = null): Promise<T | null> {
619â†’	let index = 0;
620â†’	const len = promiseFactories.length;
621â†’
622â†’	const loop: () => Promise<T | null> = () => {
623â†’		if (index >= len) {
624â†’			return Promise.resolve(defaultValue);
625â†’		}
626â†’
627â†’		const factory = promiseFactories[index++];
628â†’		const promise = Promise.resolve(factory());
629â†’
630â†’		return promise.then(result => {
631â†’			if (shouldStop(result)) {
632â†’				return Promise.resolve(result);
633â†’			}
634â†’
635â†’			return loop();
636â†’		});
637â†’	};
638â†’
639â†’	return loop();
640â†’}
