642â†’/**
643â†’ * Returns the result of the first promise that matches the "shouldStop",
644â†’ * running all promises in parallel. Supports cancelable promises.
645â†’ */
646â†’export function firstParallel<T>(promiseList: Promise<T>[], shouldStop?: (t: T) => boolean, defaultValue?: T | null): Promise<T | null>;
647â†’export function firstParallel<T, R extends T>(promiseList: Promise<T>[], shouldStop: (t: T) => t is R, defaultValue?: R | null): Promise<R | null>;
648â†’export function firstParallel<T>(promiseList: Promise<T>[], shouldStop: (t: T) => boolean = t => !!t, defaultValue: T | null = null) {
649â†’	if (promiseList.length === 0) {
650â†’		return Promise.resolve(defaultValue);
651â†’	}
652â†’
653â†’	let todo = promiseList.length;
654â†’	const finish = () => {
655â†’		todo = -1;
656â†’		for (const promise of promiseList) {
657â†’			(promise as Partial<CancelablePromise<T>>).cancel?.();
658â†’		}
659â†’	};
660â†’
661â†’	return new Promise<T | null>((resolve, reject) => {
662â†’		for (const promise of promiseList) {
663â†’			promise.then(result => {
664â†’				if (--todo >= 0 && shouldStop(result)) {
665â†’					finish();
666â†’					resolve(result);
667â†’				} else if (todo === 0) {
668â†’					resolve(defaultValue);
669â†’				}
670â†’			})
671â†’				.catch(err => {
672â†’					if (--todo >= 0) {
673â†’						finish();
674â†’						reject(err);
675â†’					}
676â†’				});
677â†’		}
678â†’	});
679â†’}
