696â†’/**
697â†’ * A helper to queue N promises and run them all with a max degree of parallelism. The helper
698â†’ * ensures that at any time no more than M promises are running at the same time.
699â†’ */
700â†’export class Limiter<T> implements ILimiter<T> {
701â†’
702â†’	private _size = 0;
703â†’	private _isDisposed = false;
704â†’	private runningPromises: number;
705â†’	private readonly maxDegreeOfParalellism: number;
706â†’	private readonly outstandingPromises: ILimitedTaskFactory<T>[];
707â†’	private readonly _onDrained: Emitter<void>;
708â†’
709â†’	constructor(maxDegreeOfParalellism: number) {
710â†’		this.maxDegreeOfParalellism = maxDegreeOfParalellism;
711â†’		this.outstandingPromises = [];
712â†’		this.runningPromises = 0;
713â†’		this._onDrained = new Emitter<void>();
714â†’	}
715â†’
716â†’	/**
717â†’	 *
718â†’	 * @returns A promise that resolved when all work is done (onDrained) or when
719â†’	 * there is nothing to do
720â†’	 */
721â†’	whenIdle(): Promise<void> {
722â†’		return this.size > 0
723â†’			? Event.toPromise(this.onDrained)
724â†’			: Promise.resolve();
725â†’	}
726â†’
727â†’	get onDrained(): Event<void> {
728â†’		return this._onDrained.event;
729â†’	}
730â†’
731â†’	get size(): number {
732â†’		return this._size;
733â†’	}
734â†’
735â†’	queue(factory: ITask<Promise<T>>): Promise<T> {
736â†’		if (this._isDisposed) {
737â†’			throw new Error('Object has been disposed');
738â†’		}
739â†’		this._size++;
740â†’
741â†’		return new Promise<T>((c, e) => {
742â†’			this.outstandingPromises.push({ factory, c, e });
743â†’			this.consume();
744â†’		});
745â†’	}
746â†’
747â†’	private consume(): void {
748â†’		while (this.outstandingPromises.length && this.runningPromises < this.maxDegreeOfParalellism) {
749â†’			const iLimitedTask = this.outstandingPromises.shift()!;
750â†’			this.runningPromises++;
751â†’
752â†’			const promise = iLimitedTask.factory();
753â†’			promise.then(iLimitedTask.c, iLimitedTask.e);
754â†’			promise.then(() => this.consumed(), () => this.consumed());
755â†’		}
756â†’	}
757â†’
758â†’	private consumed(): void {
759â†’		if (this._isDisposed) {
760â†’			return;
761â†’		}
762â†’		this.runningPromises--;
763â†’		if (--this._size === 0) {
764â†’			this._onDrained.fire();
765â†’		}
766â†’
767â†’		if (this.outstandingPromises.length > 0) {
768â†’			this.consume();
769â†’		}
770â†’	}
771â†’
772â†’	clear(): void {
773â†’		if (this._isDisposed) {
774â†’			throw new Error('Object has been disposed');
775â†’		}
776â†’		this.outstandingPromises.length = 0;
777â†’		this._size = this.runningPromises;
778â†’	}
779â†’
780â†’	dispose(): void {
781â†’		this._isDisposed = true;
782â†’		this.outstandingPromises.length = 0; // stop further processing
783â†’		this._size = 0;
784â†’		this._onDrained.dispose();
785â†’	}
786â†’}
