1415â†’//#region -- run on idle tricks ------------
1416â†’
1417â†’export interface IdleDeadline {
1418â†’	readonly didTimeout: boolean;
1419â†’	timeRemaining(): number;
1420â†’}
1421â†’
1422â†’type IdleApi = Pick<typeof globalThis, 'requestIdleCallback' | 'cancelIdleCallback'>;
1423â†’
1424â†’
1425â†’/**
1426â†’ * Execute the callback the next time the browser is idle, returning an
1427â†’ * {@link IDisposable} that will cancel the callback when disposed. This wraps
1428â†’ * [requestIdleCallback] so it will fallback to [setTimeout] if the environment
1429â†’ * doesn't support it.
1430â†’ *
1431â†’ * @param callback The callback to run when idle, this includes an
1432â†’ * [IdleDeadline] that provides the time alloted for the idle callback by the
1433â†’ * browser. Not respecting this deadline will result in a degraded user
1434â†’ * experience.
1435â†’ * @param timeout A timeout at which point to queue no longer wait for an idle
1436â†’ * callback but queue it on the regular event loop (like setTimeout). Typically
1437â†’ * this should not be used.
1438â†’ *
1439â†’ * [IdleDeadline]: https://developer.mozilla.org/en-US/docs/Web/API/IdleDeadline
1440â†’ * [requestIdleCallback]: https://developer.mozilla.org/en-US/docs/Web/API/Window/requestIdleCallback
1441â†’ * [setTimeout]: https://developer.mozilla.org/en-US/docs/Web/API/Window/setTimeout
1442â†’ *
1443â†’ * **Note** that there is `dom.ts#runWhenWindowIdle` which is better suited when running inside a browser
1444â†’ * context
1445â†’ */
1446â†’export let runWhenGlobalIdle: (callback: (idle: IdleDeadline) => void, timeout?: number) => IDisposable;
1447â†’
1448â†’export let _runWhenIdle: (targetWindow: IdleApi, callback: (idle: IdleDeadline) => void, timeout?: number) => IDisposable;
1449â†’
1450â†’(function () {
1451â†’	const safeGlobal: any = globalThis;
1452â†’	if (typeof safeGlobal.requestIdleCallback !== 'function' || typeof safeGlobal.cancelIdleCallback !== 'function') {
1453â†’		_runWhenIdle = (_targetWindow, runner, timeout?) => {
1454â†’			setTimeout0(() => {
1455â†’				if (disposed) {
1456â†’					return;
1457â†’				}
1458â†’				const end = Date.now() + 15; // one frame at 64fps
1459â†’				const deadline: IdleDeadline = {
1460â†’					didTimeout: true,
1461â†’					timeRemaining() {
1462â†’						return Math.max(0, end - Date.now());
1463â†’					}
1464â†’				};
1465â†’				runner(Object.freeze(deadline));
1466â†’			});
1467â†’			let disposed = false;
1468â†’			return {
1469â†’				dispose() {
1470â†’					if (disposed) {
1471â†’						return;
1472â†’					}
1473â†’					disposed = true;
1474â†’				}
1475â†’			};
1476â†’		};
1477â†’	} else {
1478â†’		_runWhenIdle = (targetWindow: typeof safeGlobal, runner, timeout?) => {
1479â†’			const handle: number = targetWindow.requestIdleCallback(runner, typeof timeout === 'number' ? { timeout } : undefined);
1480â†’			let disposed = false;
1481â†’			return {
1482â†’				dispose() {
1483â†’					if (disposed) {
1484â†’						return;
1485â†’					}
1486â†’					disposed = true;
1487â†’					targetWindow.cancelIdleCallback(handle);
1488â†’				}
1489â†’			};
1490â†’		};
1491â†’	}
1492â†’	runWhenGlobalIdle = (runner, timeout) => _runWhenIdle(globalThis, runner, timeout);
1493â†’})();
