1495â†’export abstract class AbstractIdleValue<T> {
1496â†’
1497â†’	private readonly _executor: () => void;
1498â†’	private readonly _handle: IDisposable;
1499â†’
1500â†’	private _didRun: boolean = false;
1501â†’	private _value?: T;
1502â†’	private _error: unknown;
1503â†’
1504â†’	constructor(targetWindow: IdleApi, executor: () => T) {
1505â†’		this._executor = () => {
1506â†’			try {
1507â†’				this._value = executor();
1508â†’			} catch (err) {
1509â†’				this._error = err;
1510â†’			} finally {
1511â†’				this._didRun = true;
1512â†’			}
1513â†’		};
1514â†’		this._handle = _runWhenIdle(targetWindow, () => this._executor());
1515â†’	}
1516â†’
1517â†’	dispose(): void {
1518â†’		this._handle.dispose();
1519â†’	}
1520â†’
1521â†’	get value(): T {
1522â†’		if (!this._didRun) {
1523â†’			this._handle.dispose();
1524â†’			this._executor();
1525â†’		}
1526â†’		if (this._error) {
1527â†’			throw this._error;
1528â†’		}
1529â†’		return this._value!;
1530â†’	}
1531â†’
1532â†’	get isInitialized(): boolean {
