1552â†’export async function retry<T>(task: ITask<Promise<T>>, delay: number, retries: number): Promise<T> {
1553â†’	let lastError: Error | undefined;
1554â†’
1555â†’	for (let i = 0; i < retries; i++) {
1556â†’		try {
1557â†’			return await task();
1558â†’		} catch (error) {
1559â†’			lastError = error;
1560â†’
1561â†’			await timeout(delay);
1562â†’		}
1563â†’	}
1564â†’
1565â†’	throw lastError;
1566â†’}
