1591â†’/**
1592â†’ * @deprecated use `LimitedQueue` instead for an easier to use API
1593â†’ */
1594â†’export class TaskSequentializer {
1595â†’
1596â†’	private _running?: IRunningTask;
1597â†’	private _queued?: IQueuedTask;
1598â†’
1599â†’	isRunning(taskId?: number): this is ITaskSequentializerWithRunningTask {

1600â†’		if (typeof taskId === 'number') {
1601â†’			return this._running?.taskId === taskId;
1602â†’		}
1603â†’
1604â†’		return !!this._running;
1605â†’	}
1606â†’
1607â†’	get running(): Promise<void> | undefined {
