1626â†’			// only set running to done if the promise finished that is associated with that taskId
1627â†’			this._running = undefined;
1628â†’
1629â†’			// schedule the queued task now that we are free if we have any
1630â†’			this.runQueued();
1631â†’		}
1632â†’	}
1633â†’
1634â†’	private runQueued(): void {
1635â†’		if (this._queued) {
1636â†’			const queued = this._queued;
1637â†’			this._queued = undefined;
1638â†’
1639â†’			// Run queued task and complete on the associated promise
1640â†’			queued.run().then(queued.promiseResolve, queued.promiseReject);
1641â†’		}
1642â†’	}
