1658â†’				run,
1659â†’				promise,
1660â†’				promiseResolve,
1661â†’				promiseReject
1662â†’			};
1663â†’		}
1664â†’
1665â†’		// we have a previous queued task, just overwrite it
1666â†’		else {
1667â†’			this._queued.run = run;
1668â†’		}
1669â†’
1670â†’		return this._queued.promise;
1671â†’	}
1672â†’
1673â†’	hasQueued(): this is ITaskSequentializerWithQueuedTask {
1674â†’		return !!this._queued;
1675â†’	}
1676â†’
1677â†’	async join(): Promise<void> {
1678â†’		return this._queued?.promise ?? this._running?.promise;
1679â†’	}
1680â†’}
