1693â†’export class IntervalCounter {
1694â†’
1695â†’	private lastIncrementTime = 0;
1696â†’
1697â†’	private value = 0;
1698â†’
1699â†’	constructor(private readonly interval: number, private readonly nowFn = () => Date.now()) { }
1700â†’
1701â†’	increment(): number {
